VALUES
  ('heelevel3-c8735cdb-moex-00019', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '稱普通抵押權者，謂債權人對於債務人或第三人不移轉占有而供其債權擔保之不動產，得就該不 動產賣得價金優先受償之權。下列何者，不為普通抵押權效力所及？', '["以建築物為抵押者，其附加於該建築物，具獨立性之部分", "抵押物之從物", "抵押物扣押後，自抵押物分離，而得由抵押人收取之天然孳息", "抵押物滅失後之殘餘物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00020', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '下列何者不得辦理登記以對抗第三人？', '["不動產共有人關於共有物之使用管理約定", "地上權之預付地租", "區分地上權人與其設定之土地上下有使用收益權利之人，相互間關於使用收益之限制約定", "不動產共有人關於應有部分轉讓之限制約定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00021', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '21歲獨子乙趁甲父病重，將甲所有之傳家A鑽戒變賣於惡意丙，為避免被發現，乙、丙間約定以 占有改定方式交付，甲得知此事後氣絕身亡，由乙唯一繼承甲之財產。乙欲將A鑽戒再次交付於 丙，因丙暫時出國，雙方商量後約定委託丁轉交。此時A鑽戒所有權之歸屬？', '["甲", "乙", "丙", "丁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00022', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '下列關於普通地上權存續期間規定之敘述，何者正確？', '["定有期限之地上權，為達土地利用目的，其存續期間不得低於一年以下", "定有期限之地上權，其存續期間逾三十年者，縮短為三十年", "未定有期限之地上權，其存續期間逾二十年者，當事人一方得自行終止其地上權", "未定有期限之地上權，如係以公共建設為目的而成立者，以該建設使用目的完畢時，視為地上 權之存續期限 23520"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00023', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '下列何者非為民法上之物權？', '["不動產役權", "典權", "權利質權", "遺產之使用收益權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00024', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '下列關於不動產所有權之取得或移轉，何者應辦理登記，始發生效力？', '["私人土地之徵收", "法院強制執行拍賣債務人名下之土地，而由他人拍定", "私人拋棄其土地所有權", "私人蓋好房屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00025', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲男乙女為夫妻，甲竟與乙之姪女丙發生姦情。乙訴請判決離婚，判決確定之一個月後，甲與丙 結婚。下列敘述，何者正確？', '["甲丙違反待婚期間之限制，其婚姻得撤銷", "甲丙違反相姦婚禁止之規定，其婚姻得撤銷", "甲丙違反近親結婚之限制，其婚姻無效", "甲丙並未違反規定，其婚姻有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00026', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '遺產分割後，其未清償之被繼承人之債務，移歸一定之人承受，或劃歸各繼承人分擔，如經債權 人同意者，各繼承人得免除何種責任？', '["連帶保證", "連帶責任", "連帶債權", "侵權責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00027', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲、乙為夫妻，無子女。甲之父母均已死亡，甲有兄弟丙、丁二人。甲生前曾向丙借款新臺幣（下 同）40萬元，尚未清償。甲死亡時，留有遺產200萬元。遺產分割時，丙可分得多少財產？', '["60萬元", "70萬元", "80萬元", "90萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00028', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲男乙女於民國112年1月間結婚，甲於結婚前，有勞力所得新臺幣（下同）60萬元。下列關於 夫妻財產之敘述，何者正確？', '["設甲乙約定採共同財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙約定採分別財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙未約定夫妻財產制，甲勞力所得之60萬元，由甲乙公同共有", "設甲乙約定採勞力所得共同財產制，甲勞力所得之60萬元，由甲單獨所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL)
